1	import { Router } from "express";
2	import { products } from "../data.js";
3	
4	const router = Router();
5	
6	// GET /products - list all products, optionally filter by category
7	router.get("/products", (req, res) => {
8	  const { category, minPrice, maxPrice } = req.query;
9	
10	  let filtered = [...products];
11	
12	  if (category && typeof category === "string") {
13	    filtered = filtered.filter((p) => p.category === category);
14	  }
15	
16	  if (minPrice && typeof minPrice === "string") {
17	    const min = parseFloat(minPrice);
18	    if (!isNaN(min)) {
19	      filtered = filtered.filter((p) => p.price >= min);
20	    }
21	  }
22	
23	  if (maxPrice && typeof maxPrice === "string") {
24	    const max = parseFloat(maxPrice);
25	    if (!isNaN(max)) {
26	      filtered = filtered.filter((p) => p.price <= max);
27	    }
28	  }
29	
30	  // Calculate summary stats
31	  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
32	  const avgPrice =
33	    filtered.length > 0
34	      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
35	      : 0;
36	
37	  res.json({
38	    products: filtered,
39	    summary: {
40	      count: filtered.length,
41	      totalInventoryValue: Math.round(totalValue * 100) / 100,
42	      averagePrice: Math.round(avgPrice * 100) / 100,
43	    },
44	  });
45	});
46	
47	// GET /products/:id
48	router.get("/products/:id", (req, res) => {
49	  const id = parseInt(req.params.id, 10);
50	  const product = products.find((p) => p.id === id);
51	
52	  if (!product) {
53	    res.status(404).json({ error: "Product not found" });
54	    return;
55	  }
56	
57	  // Calculate if product is low stock
58	  const isLowStock = product.stock < 10;
59	  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;
60	
61	  res.json({
62	    ...product,
63	    isLowStock,
64	    inventoryValue,
65	  });
66	});
67	
68	// PATCH /products/:id/stock - update stock
69	router.patch("/products/:id/stock", (req, res) => {
70	  const id = parseInt(req.params.id, 10);
71	  const product = products.find((p) => p.id === id);
72	
73	  if (!product) {
74	    res.status(404).json({ error: "Product not found" });
75	    return;
76	  }
77	
78	  const { adjustment } = req.body as { adjustment: number };
79	  if (typeof adjustment !== "number") {
80	    res.status(400).json({ error: "adjustment must be a number" });
81	    return;
82	  }
83	
84	  const newStock = product.stock + adjustment;
85	  if (newStock < 0) {
86	    res.status(400).json({ error: "Insufficient stock" });
87	    return;
88	  }
89	
90	  product.stock = newStock;
91	
92	  res.json({
93	    ...product,
94	    isLowStock: product.stock < 10,
95	    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
96	  });
97	});
98	
99	export { router as productRouter };
100	

