  userId?: number;
  status?: string;
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}
```

**Function signatures:**

```typescript
export function listOrders(filters: OrderFilters): OrderListResult

export function getOrder(id: number): EnrichedOrder
// throws ServiceError(404) if not found

export function createOrder(input: CreateOrderInput): Order
// throws ServiceError(400) if userId missing, items missing/not array, or items empty
// throws ServiceError(400) if any productId not found
// throws ServiceError(400) if any quantity <= 0
// throws ServiceError(400) if insufficient stock
// mutates product.stock; pushes to orders[]

export function updateOrderStatus(id: number, status: string): Order
// throws ServiceError(404) if not found
// throws ServiceError(400) if status not in valid set
// throws ServiceError(400) if transition not allowed
// mutates order.status
```

**Logic to move:**

- `listOrders`: `userId` and `status` filter branches, `totalRevenue` reduction, rounding.
- `getOrder`: `.find()`, `enrichedItems` map with `productName` lookup.
- `createOrder`: all validation loops, stock deduction, `orderItems` accumulation, `total` computation, object construction, `orders.push()`.
- `updateOrderStatus`: `.find()`, `validStatuses` check, `transitions` state machine check, `order.status` mutation.

---

### Step 4: Refactor `src/routes/products.ts`

The refactored route file will:
1. Import `listProducts`, `getProduct`, `adjustStock` from `../services/product-service.js`.
2. Import `ServiceError` from `../types.js`.
3. Each handler parses its inputs, calls the service in a try/catch, and either sends the result or handles `ServiceError`.

**Pattern for every handler:**

```typescript
router.get("/products", (req, res) => {
  const filters: ProductFilters = {
    category: typeof req.query.category === "string" ? req.query.category : undefined,
    minPrice: typeof req.query.minPrice === "string" ? parseFloat(req.query.minPrice) : undefined,
    maxPrice: typeof req.query.maxPrice === "string" ? parseFloat(req.query.maxPrice) : undefined,
  };
  res.json(listProducts(filters));
});

router.get("/products/:id", (req, res) => {
  try {
    res.json(getProduct(parseInt(req.params.id, 10)));
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.httpStatus).json({ error: err.message });
    } else throw err;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  const { adjustment } = req.body as { adjustment: unknown };
  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }
  try {
    res.json(adjustStock(parseInt(req.params.id, 10), adjustment));
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.httpStatus).json({ error: err.message });
    } else throw err;
  }
});
```

