import { Router } from "express";
import {
  listProducts,
  getProduct,
  adjustStock,
} from "../services/product-service.js";
import type { ProductFilters } from "../services/product-service.js";
import { ServiceError } from "../types.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters: ProductFilters = {
    category: typeof category === "string" ? category : undefined,
    minPrice:
      typeof minPrice === "string" ? parseFloat(minPrice) : undefined,
    maxPrice:
      typeof maxPrice === "string" ? parseFloat(maxPrice) : undefined,
  };

  res.json(listProducts(filters));
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);

  try {
    res.json(getProduct(id));
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.httpStatus).json({ error: err.message });
    } else {
      throw err;
    }
  }
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: unknown };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  try {
    res.json(adjustStock(id, adjustment));
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.httpStatus).json({ error: err.message });
    } else {
      throw err;
    }
  }
});

export { router as productRouter };

